import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { LogIn, Mail, Lock, LogOut, ShieldCheck, FileText, Activity, UserPlus, Plus, X, Clock, CheckCircle, Upload, Settings } from 'lucide-react';

const Login = () => {
  const [isRegistering, setIsRegistering] = useState(false);
  const [formData, setFormData] = useState({ name: '', email: '', password: '' });
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [isAdmin, setIsAdmin] = useState(false); // NEW: Admin Role
  const [showModal, setShowModal] = useState(false);
  const [activeTab, setActiveTab] = useState('tracking'); // NEW: Tab system

  // NEW: Shared State for Credential Requests
  const [requests, setRequests] = useState([
    { id: 101, type: 'Medical License', status: 'Approved', date: '2026-04-10' },
    { id: 102, type: 'DEA Certification', status: 'Pending', date: '2026-04-15' }
  ]);

  useEffect(() => {
    const token = localStorage.getItem('token');
    const email = localStorage.getItem('userEmail');
    if (token) {
      setIsLoggedIn(true);
      if (email?.includes('admin')) setIsAdmin(true); // Simple Admin simulation
    }
  }, []);

  const handleAuth = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.post(`http://localhost:5000/api/auth/${isRegistering ? 'register' : 'login'}`, formData);
      if (!isRegistering) {
        localStorage.setItem('token', res.data.token);
        localStorage.setItem('userName', res.data.user.name);
        localStorage.setItem('userRole', res.data.user.role);//get the real role from DB
        setIsLoggedIn(true);
        if (res.data.user.role === 'admin' ) setIsAdmin(true); //Secure check
      } else {
        setIsRegistering(false);
        alert("Registration Successful!");
      }
    } catch (err) { 
        alert("Invalid Credentials");
     }
  };

  const submitRequest = (e) => {
    e.preventDefault();
    const newReq = { id: Math.floor(Math.random() * 1000), type: e.target[0].value, status: 'Pending', date: new Date().toISOString().split('T')[0] };
    setRequests([newReq, ...requests]);
    setShowModal(false);
  };

  const updateStatus = (id, newStatus) => {
    setRequests(requests.map(r => r.id === id ? { ...r, status: newStatus } : r));
  };

  if (isLoggedIn) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col font-sans">
        {/* Navbar */}
        <nav className="bg-white shadow-sm border-b p-4 sticky top-0 z-50">
          <div className="max-w-7xl mx-auto flex justify-between items-center">
            <h1 className="text-xl font-black text-blue-600 tracking-tight italic">QUAD SOLUTIONS {isAdmin && <span className="text-xs bg-red-100 text-red-600 px-2 py-1 rounded ml-2">ADMIN</span>}</h1>
            <div className="flex gap-4">
               <button onClick={() => setActiveTab('tracking')} className={`text-sm font-bold ${activeTab === 'tracking' ? 'text-blue-600' : 'text-gray-400'}`}>Tracking</button>
               {isAdmin && <button onClick={() => setActiveTab('admin')} className={`text-sm font-bold ${activeTab === 'admin' ? 'text-blue-600' : 'text-gray-400'}`}>Admin Panel</button>}
               <button onClick={() => {localStorage.clear(); window.location.reload();}} className="text-red-500 font-bold text-sm">Logout</button>
            </div>
          </div>
        </nav>

        <main className="p-6 max-w-7xl mx-auto w-full">
          {/* 1. Client Onboarding / Dashboard Header */}
          <div className="flex justify-between items-center mb-8">
            <h2 className="text-2xl font-black">{isAdmin ? "Admin Management" : "My Credentialing Status"}</h2>
            {!isAdmin && <button onClick={() => setShowModal(true)} className="bg-blue-600 text-white px-4 py-2 rounded-xl font-bold flex items-center gap-2"><Upload size={18}/> Submit Request</button>}
          </div>

          {/* 2. ADMIN DASHBOARD VIEW */}
          {activeTab === 'admin' && isAdmin ? (
            <div className="bg-white rounded-2xl shadow-sm border p-6">
              <h3 className="font-bold mb-4 text-gray-500 uppercase text-xs tracking-widest">Global Requests Queue</h3>
              <div className="space-y-4">
                {requests.map(req => (
                  <div key={req.id} className="flex items-center justify-between p-4 bg-slate-50 rounded-xl border border-slate-100">
                    <div>
                      <p className="font-bold text-slate-800">{req.type} <span className="text-xs text-slate-400 font-normal">#ID-{req.id}</span></p>
                      <p className="text-xs text-slate-500">Submitted on: {req.date}</p>
                    </div>
                    <div className="flex gap-2">
                      <button onClick={() => updateStatus(req.id, 'Approved')} className="p-2 bg-green-100 text-green-600 rounded-lg hover:bg-green-200"><CheckCircle size={18}/></button>
                      <button onClick={() => updateStatus(req.id, 'Rejected')} className="p-2 bg-red-100 text-red-600 rounded-lg hover:bg-red-200"><X size={18}/></button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ) : (
            /* 3. STATUS TRACKING SYSTEM (CLIENT VIEW) */
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="bg-white p-6 rounded-2xl shadow-sm border">
                <h3 className="font-bold mb-4 flex items-center gap-2 text-blue-600"><Clock size={20}/> Active Tracking</h3>
                <div className="space-y-3">
                  {requests.map(req => (
                    <div key={req.id} className="flex justify-between items-center p-3 border-b last:border-0">
                      <span className="font-medium text-slate-700">{req.type}</span>
                      <span className={`text-[10px] uppercase px-2 py-1 rounded-full font-black ${req.status === 'Approved' ? 'bg-green-100 text-green-600' : req.status === 'Rejected' ? 'bg-red-100 text-red-600' : 'bg-yellow-100 text-yellow-600'}`}>
                        {req.status}
                      </span>
                    </div>
                  ))}
                </div>
              </div>

              {/* 4. DOCUMENT HANDLING SECTION */}
              <div className="bg-white p-6 rounded-2xl shadow-sm border">
                <h3 className="font-bold mb-4 flex items-center gap-2 text-emerald-600"><FileText size={20}/> Handled Documents</h3>
                <div className="grid grid-cols-2 gap-3 text-center">
                   <div className="p-4 bg-slate-50 rounded-xl border border-dashed border-slate-200 hover:bg-emerald-50 cursor-pointer transition">
                      <FileText className="mx-auto mb-2 text-slate-400" size={24}/>
                      <p className="text-[10px] font-bold text-slate-500">License_Main.pdf</p>
                   </div>
                   <div className="p-4 bg-slate-50 rounded-xl border border-dashed border-slate-200 hover:bg-emerald-50 cursor-pointer transition">
                      <ShieldCheck className="mx-auto mb-2 text-slate-400" size={24}/>
                      <p className="text-[10px] font-bold text-slate-500">DEA_Cert.jpg</p>
                   </div>
                </div>
              </div>
            </div>
          )}
        </main>

        {/* --- MODAL FOR REQUEST SUBMISSION --- */}
        {showModal && (
          <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm flex items-center justify-center p-4 z-[100]">
            <div className="bg-white w-full max-w-md rounded-3xl shadow-2xl p-8">
              <h2 className="text-xl font-bold mb-4">Submit Credentialing Request</h2>
              <form onSubmit={submitRequest} className="space-y-4">
                <select className="w-full p-3 bg-slate-50 rounded-xl border-none font-medium">
                  <option>Medical License Renewal</option>
                  <option>Board Certification</option>
                  <option>Insurance Panel Enrollment</option>
                </select>
                <div className="p-10 border-2 border-dashed border-slate-200 rounded-2xl text-center text-slate-400">
                  <Upload size={32} className="mx-auto mb-2"/>
                  <p className="text-xs">Drag & Drop Documents Here</p>
                </div>
                <button className="w-full bg-blue-600 text-white py-3 rounded-xl font-bold">Submit to Admin</button>
                <button onClick={() => setShowModal(false)} className="w-full text-slate-400 text-sm">Cancel</button>
              </form>
            </div>
          </div>
        )}
      </div>
    );
  }

  // --- LOGIN UI (SAME AS BEFORE) ---
  return (
    <div className="flex items-center justify-center min-h-screen bg-slate-100 p-4">
      <div className="w-full max-w-md bg-white p-10 rounded-[2.5rem] shadow-2xl border-t-8 border-blue-600">
        <h2 className="text-3xl font-black text-center mb-6">QuadSolutions</h2>
        <form onSubmit={handleAuth} className="space-y-4">
          {isRegistering && <input type="text" placeholder="Full Name" className="w-full px-5 py-4 rounded-2xl bg-slate-50" onChange={(e) => setFormData({...formData, name: e.target.value})} required />}
          <input type="email" placeholder="Email (use 'admin@test.com' for Admin View)" className="w-full px-5 py-4 rounded-2xl bg-slate-50" onChange={(e) => setFormData({...formData, email: e.target.value})} required />
          <input type="password" placeholder="Password" className="w-full px-5 py-4 rounded-2xl bg-slate-50" onChange={(e) => setFormData({...formData, password: e.target.value})} required />
          <button className="w-full bg-blue-600 py-4 rounded-2xl text-white font-bold">{isRegistering ? "Register" : "Login"}</button>
        </form>
        <button onClick={() => setIsRegistering(!isRegistering)} className="w-full mt-4 text-slate-400 font-bold">{isRegistering ? "Login" : "Register"}</button>
      </div>
    </div>
  );
};

export default Login;
